) {
    fun loadFrom(file: File) {
        val properties = Properties().apply {
            file.inputStream().buffered().use { input ->
                load(input)
            }
        }
        uuid = properties.getProperty(UUID) ?: uuid
        uploadTime = properties.getProperty(UPLOAD_TIME) ?: uploadTime
