        properties[UPLOAD_TIME] = uploadTime
        file.outputStream().buffered().use { output ->
            properties.store(output, null)
        }
    }

    companion object {
        private const val UUID = "uuid"
        private const val UPLOAD_TIME = "upload.time"
    }
}

